    chunks := [][]rune{
        {'a', 'c', 'e'},
        {'b', 'd', 'f'},
        {'g', 'h'},
    }

    merged := solution.Merge(chunks)
    fmt.Println("Merged Array:", string(merged))
    solution.MergeInPlace(chunks)
}
