                                    std::make_pair(rank[suffix_array[i - 1]], suffix_array[i - 1] + chunk_size &lt; text_length ? rank[suffix_array[i - 1] + chunk_size] : -1));
                }
                for (int i = 0; i &lt; text_length; ++i) {
                    rank[suffix_array[i]] = temp_rank[i];
