                rank[suffix_array[i]] = i;
            }
            int k = 0;
            for (int i = 0; i &lt; text_length; ++i) {
                if (rank[i] == text_length - 1) {
                    k = 0;
                    continue;
                }
                int j = suffix_array[rank[i] + 1];
                while (i + k &lt; text_length &amp;&amp; j + k &lt; text_length &amp;&amp; text[i + k] == text[j + k]) {
                    k++;
                }
                lcp[rank[i]] = k;
                if (k) {
