        if (!head || !head-&gt;next) {
            return head;
        }
        ListNode* newHead = nullptr;
        ListNode* prev = nullptr;
        ListNode* curr = head;

        while (curr) {
            prev = curr;
            curr = curr-&gt;next.value_or(nullptr);
            prev-&gt;next = newHead;
            newHead = prev;
        }

        return prev;
